VALUES
  ('optician-moex-01819', 'optician', 'optician-moex-108-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '一患者右眼處方：-4.00 DS；左眼處方：-3.50 DS；其瞳距為62 mm，若選用過大的鏡框導致雙眼鏡片光 心間距離需放大至66 mm才可製作，則所產生的稜鏡量為何？', '["右眼0.8Δ基底向內；左眼0.7Δ基底向內", "右眼 1 Δ基底向內；左眼0.8Δ基底向內", "右眼1.2Δ基底向外；左眼 1Δ基底向外", "右眼0.5Δ基底向外；左眼0.4Δ基底向外"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "8df8b65115b1", "answer_pdf_sha1": "d875f69b2637", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01820', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡材質中加入甲基丙烯酸甲酯（methyl methacrylate），不會產生何種變化？', '["增加硬度", "清晰的光學性", "材質更穩定", "提高透氧性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01821', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '軟式水膠隱形眼鏡的傳氧率（oxygen transmissibility, Dk/L），下列敍述何者錯誤？', '["減少鏡片的厚度可增加傳氧率", "增加含水量增加傳氧率", "要避免角膜水腫，日戴型隱形眼鏡（daily wear, DW）所需要的傳氧率會比長戴型的軟式隱形眼鏡 （extended wear, EW）要低", "在厚度不變時，減少鏡片材質的擴散係數（diffusivity）可增加傳氧率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01822', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有一片硬式隱形眼鏡直徑為9.2 mm，請問此鏡片最有可能為下列何者？', '["角膜鏡（corneal lens）", "角膜鞏膜鏡（corneo-scleral lens）", "微型鞏膜鏡（miniscleral lens）", "鞏膜鏡（scleral lens）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01823', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '對於選擇適合的隱形眼鏡與敘述，何者正確？', '["角膜塑型鏡（orthokeratology）依目前的研究不可能減緩近視的發展", "對於老花患者，配戴軟式多焦點隱形眼鏡比配戴其他類型的隱形眼鏡更能提供較好的視覺品質", "有圓錐角膜或是屈光術後產生之不規則散光，相較軟式隱形眼鏡，較適合使用硬式透氣隱形眼鏡（RGP）", "因配戴隱形眼鏡而發生感染的患者，建議改用矽水膠材質的隱形眼鏡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01824', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式水膠隱形眼鏡的材質，何者有較高的透氧性？', '["NVP（N-vinyl pyrrolidone）", "HEMA（2-hydroxyethyl methacrylate）", "MMA（methyl methacrylate）", "GMA（glyceryl methacrylate）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01825', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡的製作方法，何者正確？', '["旋轉成型（spin casting）的旋轉速度若較快，會產生較平的後表面弧度", "拋棄式隱形眼鏡較常使用車床切割（lathe cutting）來製作", "鑄模成型（cast molding）通常用來製作PMMA和GP鏡片", "旋轉成型最大的問題是定位，通常會較偏向鼻側"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 6, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01826', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡的薄鏡片敘述，下列何者錯誤？', '["與同材質鏡片相比，薄鏡片較透氧", "薄鏡片矯正散光的效果好，因為所造成之淚鏡效應可有效矯正角膜散光", "配戴舒適感高，因較柔軟", "易服貼角膜表面，所以驗配容易"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01827', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '屈光手術後和不規則角膜的首選材質為何？', '["硬式高透氧鏡片", "矽水膠鏡片", "水膠加厚片", "水膠超薄片"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01828', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '驗光度數為-2.00DS/-1.50DC×170，當為其配戴散光隱形眼鏡，試片中心貼附良好，但鏡片指標從 6 點鐘 偏移至7點鐘方向，該驗配的隱形眼鏡度數應為：', '["-2.00DS/-1.50DC×170", "-2.00DS/-1.50DC×020", "-2.00DS/-1.50DC×140", "-2.00DS/-1.50DC×155"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
